const MEALS = [ { id:1, meal:"Honey Garlic Chicken Thighs", description:"Sticky, savory chicken everyone asks for again.", prepTime:"10 min", cookTime:"25 min", cost:"$10–12", calories:520, protein:"38g", carbs:"22g", fat:"18g", fiber:"1g", proteinType:"Chicken", proteinHeavy:true, carbHeavy:false, ingredients:["2 lbs bone-in chicken thighs","4 cloves garlic, minced","3 tbsp honey","2 tbsp soy sauce","1 tbsp olive oil","1 tsp paprika","Salt & pepper","Fresh parsley"], steps:["Preheat oven to 400°F. Season chicken with paprika, salt, pepper.","Sear skin-side down in oven-safe skillet 4 min.","Flip, add garlic 1 min. Pour honey + soy sauce over top.","Bake 25 min until cooked through.","Spoon pan juices over chicken before serving."], pickyVersion:"Plain baked chicken before adding any sauce.", portionNotes:"Toddlers: ½ thigh shredded. Kids: 1 thigh. Teens & adults: 1–2 thighs.", veggieAlt:{ meal:"Black Bean & Sweet Potato Enchiladas", prepTime:"15 min", cookTime:"25 min", cost:"+$3", calories:490, protein:"18g", carbs:"62g", fat:"16g", fiber:"12g", ingredients:["1 can black beans","1 sweet potato, cubed & roasted","2 flour tortillas","½ cup enchilada sauce","½ cup shredded cheese","½ tsp cumin"], steps:["Roast sweet potato at 400°F for 20 min.","Mix beans + sweet potato + cumin.","Fill tortillas, roll tight, place in dish.","Pour enchilada sauce + cheese on top.","Bake 20 min until bubbly."], vegNote:"Same oven, same temp — roast sweet potato right alongside the chicken!" } }, { id:2, meal:"Beef & Veggie Taco Night", description:"Build-your-own tacos — everyone gets exactly what they want.", prepTime:"10 min", cookTime:"15 min", cost:"$12–14", calories:480, protein:"32g", carbs:"38g", fat:"16g", fiber:"5g", proteinType:"Beef", proteinHeavy:true, carbHeavy:false, ingredients:["1.5 lbs ground beef","1 packet taco seasoning","8 small flour tortillas","1 can black beans","1 cup shredded cheddar","Lettuce, tomatoes, sour cream, salsa"], steps:["Brown ground beef, drain fat.","Add taco seasoning + ½ cup water. Simmer 5 min.","Warm beans and tortillas.","Set up a taco bar with all the toppings.","Let everyone build their own — the kids will love it!"], pickyVersion:"Plain ground beef in a plain tortilla with just cheese.", portionNotes:"Toddlers: 1 small soft taco, fillings on the side. Kids: 2 tacos. Teens & adults: 2–3 tacos.", veggieAlt:{ meal:"Black Bean Tacos with Avocado", prepTime:"5 min", cookTime:"5 min", cost:"+$2", calories:440, protein:"16g", carbs:"54g", fat:"18g", fiber:"14g", ingredients:["1 can black beans","½ ripe avocado, mashed","2 small flour tortillas","¼ cup shredded cheddar","Salsa & lime"], steps:["Heat beans with a pinch of cumin.","Mash avocado with lime juice and salt.","Warm tortillas in a dry pan.","Top with avocado, beans, and cheese.","Add salsa and extra lime to taste."], vegNote:"Same taco bar — just swap in beans and avocado!" } }, { id:3, meal:"Sheet Pan Pork Tenderloin & Veggies", description:"One pan, minimal cleanup — dinner practically makes itself.", prepTime:"10 min", cookTime:"30 min", cost:"$11–13", calories:490, protein:"42g", carbs:"28g", fat:"14g", fiber:"4g", proteinType:"Pork", proteinHeavy:true, carbHeavy:false, ingredients:["1.5 lbs pork tenderloin","3 medium potatoes, cubed","2 bell peppers, sliced","1 zucchini, sliced","3 tbsp olive oil","2 tsp garlic powder","1 tsp dried rosemary","Salt & pepper"], steps:["Preheat oven to 425°F. Line a large sheet pan with foil.","Toss vegetables with olive oil and seasonings. Spread on pan.","Season pork with salt, pepper, garlic powder. Place on pan.","Roast 25–30 min until pork reaches 145°F.","Rest 5 min, slice and serve over the roasted vegetables."], pickyVersion:"Plate plain pork and plain roasted potatoes separately before tossing with other veggies.", portionNotes:"Toddlers: small pieces + soft potato. Kids: 3–4 oz pork. Teens & adults: 5–6 oz.", veggieAlt:{ meal:"Egg & Veggie Sheet Pan Bake", prepTime:"5 min", cookTime:"30 min", cost:"+$2", calories:390, protein:"24g", carbs:"28g", fat:"20g", fiber:"5g", ingredients:["3 large eggs","1 cup cubed potato (from family batch)","1 bell pepper, diced","½ zucchini, sliced","1 tbsp olive oil","½ cup shredded cheddar"], steps:["Toss veggies with olive oil and seasonings.","Roast on a foil-divided section of the same pan, 25 min.","Scoop into a small oven-safe dish.","Crack eggs over the top, sprinkle with cheese.","Return to oven 8 min until eggs are just set."], vegNote:"Same pan, same oven — just a foil divider separates the sections!" } }, { id:4, meal:"Chicken Fried Rice", description:"Better than takeout and a great way to use up leftover rice.", prepTime:"10 min", cookTime:"20 min", cost:"$8–10", calories:440, protein:"28g", carbs:"52g", fat:"12g", fiber:"3g", proteinType:"Chicken", proteinHeavy:false, carbHeavy:true, ingredients:["2 cups day-old cooked rice","1 lb chicken breast, diced","3 eggs, beaten","1 cup frozen peas & carrots","3 tbsp soy sauce","2 tbsp sesame oil","3 green onions, sliced","2 cloves garlic, minced"], steps:["Cook chicken in sesame oil over high heat. Set aside.","Cook garlic 30 sec. Push aside and scramble eggs in center.","Add peas and carrots, stir fry 2 min. Add rice, break up clumps.","Return chicken, add soy sauce. Toss everything over high heat 3 min.","Top with green onions and serve hot."], pickyVersion:"Serve plain chicken and plain rice with soy sauce on the side for dipping.", portionNotes:"Toddlers: ½ cup, chicken shredded fine. Kids: 1 cup. Teens & adults: 1.5–2 cups.", veggieAlt:{ meal:"Veggie & Tofu Fried Rice", prepTime:"10 min", cookTime:"15 min", cost:"+$3", calories:420, protein:"22g", carbs:"50g", fat:"14g", fiber:"5g", ingredients:["1 cup day-old rice","½ block firm tofu, cubed","2 eggs, beaten","½ cup peas & carrots (from family batch)","1.5 tbsp soy sauce","1 tbsp sesame oil","1 green onion"], steps:["Press tofu dry. Fry in sesame oil until golden, 4–5 min.","Scramble eggs in the same pan.","Add veggies 2 min, add rice and break up clumps.","Return tofu, add soy sauce. Toss 2 min.","Top with green onion."], vegNote:"Same wok, same sauce — just tofu swapped in for chicken!" } }, { id:5, meal:"Slow Cooker BBQ Pulled Pork Sliders", description:"Set it in the morning — come home to the most amazing smell.", prepTime:"15 min", cookTime:"8 hrs", cost:"$13–15", calories:510, protein:"36g", carbs:"42g", fat:"16g", fiber:"2g", proteinType:"Pork", proteinHeavy:true, carbHeavy:false, ingredients:["2.5 lbs pork shoulder","1 cup BBQ sauce","½ cup chicken broth","1 tbsp brown sugar","1 tsp garlic powder","1 tsp onion powder","12 slider buns","Coleslaw to serve"], steps:["Mix broth, brown sugar, garlic powder and onion powder. Pour into slow cooker.","Add pork. Cook on LOW 8 hours or HIGH 4–5 hours.","Remove pork and shred with two forks. Discard excess liquid.","Return pork to slow cooker, stir in BBQ sauce. Cook LOW 30 more min.","Pile onto slider buns and top with coleslaw."], pickyVersion:"Set aside plain shredded pork before mixing with BBQ sauce. Serve on a plain bun.", portionNotes:"Toddlers: shredded pork, no bun. Kids: 1–2 sliders. Teens & adults: 2–3 sliders.", veggieAlt:{ meal:"BBQ Chickpea Sliders", prepTime:"5 min", cookTime:"10 min", cost:"+$2", calories:440, protein:"16g", carbs:"58g", fat:"12g", fiber:"10g", ingredients:["1 can chickpeas, drained","3 tbsp BBQ sauce","2 slider buns","Coleslaw (from the family batch)","½ tsp smoked paprika"], steps:["Heat chickpeas with paprika 3 min.","Add BBQ sauce, stir to coat.","Lightly mash about half for better texture.","Pile onto slider buns.","Top with coleslaw."], vegNote:"Same buns, same coleslaw as the family's pulled pork!" } }, { id:6, meal:"Classic Beef Chili", description:"Hearty, warming, and even better the next day for lunch.", prepTime:"10 min", cookTime:"35 min", cost:"$10–12", calories:500, protein:"34g", carbs:"44g", fat:"14g", fiber:"10g", proteinType:"Beef", proteinHeavy:true, carbHeavy:false, ingredients:["1.5 lbs ground beef","2 cans kidney beans, drained","1 can crushed tomatoes","1 can diced tomatoes","1 onion, diced","3 cloves garlic","2 tbsp chili powder","1 tsp cumin"], steps:["Brown ground beef with onion. Drain fat.","Add garlic, chili powder and cumin. Cook 1 min.","Add both cans of tomatoes and the beans.","Bring to a boil then simmer uncovered 25–30 min.","Serve with shredded cheese and sour cream."], pickyVersion:"Ladle out plain beef and beans before adding the spices. Serve with plain rice.", portionNotes:"Toddlers: mild portion, ½ cup. Kids: 1 cup. Teens & adults: 1.5–2 cups.", veggieAlt:{ meal:"Three-Bean Vegetarian Chili", prepTime:"5 min", cookTime:"30 min", cost:"+$3", calories:450, protein:"22g", carbs:"62g", fat:"8g", fiber:"18g", ingredients:["1 can black beans","1 can kidney beans","1 can pinto beans — all drained","1 can diced tomatoes","1 tbsp chili powder","½ tsp cumin"], steps:["Sauté onion in olive oil 4 min.","Add garlic, chili powder and cumin. Cook 1 min.","Add all beans and tomatoes. Stir well.","Simmer uncovered 20 min until thickened.","Serve with cheese and sour cream."], vegNote:"Same pot, same spices — just beans instead of beef!" } }, { id:7, meal:"Lemon Herb Baked Salmon", description:"Light, healthy, and impressive enough for a dinner party.", prepTime:"5 min", cookTime:"18 min", cost:"$14–16", calories:420, protein:"44g", carbs:"8g", fat:"22g", fiber:"1g", proteinType:"Fish", proteinHeavy:true, carbHeavy:false, ingredients:["4 salmon fillets","2 tbsp olive oil","2 cloves garlic, minced","1 lemon, sliced","1 tsp dried dill","1 tsp dried parsley","Salt & pepper","Steamed broccoli to serve"], steps:["Preheat oven to 400°F. Line a baking dish with foil.","Place salmon fillets in dish and drizzle with olive oil.","Top with minced garlic, lemon slices, dill, parsley, salt and pepper.","Bake 15–18 min until salmon flakes easily with a fork.","Serve with steamed broccoli and extra lemon."], pickyVersion:"Plain baked salmon with plain rice — hold the herbs and lemon.", portionNotes:"Toddlers: flaked, small portion. Kids: 3 oz fillet. Teens & adults: 5–6 oz.", veggieAlt:{ meal:"Lemon Garlic White Beans & Broccoli", prepTime:"5 min", cookTime:"20 min", cost:"+$2", calories:380, protein:"18g", carbs:"48g", fat:"12g", fiber:"12g", ingredients:["1 can white beans, drained","1 cup broccoli florets","1 cup cherry tomatoes","2 tbsp olive oil","1 lemon, sliced","1 tsp dried herbs","Salt & pepper"], steps:["Preheat oven to 400°F (same as salmon).","Toss beans and veggies with olive oil, herbs, salt, pepper.","Spread on a foil-lined sheet with lemon slices on top.","Roast 20 min until edges are golden.","Squeeze extra lemon over top before serving."], vegNote:"Same oven, same temperature — roasts right alongside the salmon!" } }, { id:8, meal:"Garlic Butter Shrimp Pasta", description:"Restaurant-quality shrimp pasta ready in under 20 minutes.", prepTime:"5 min", cookTime:"15 min", cost:"$12–14", calories:490, protein:"36g", carbs:"48g", fat:"16g", fiber:"2g", proteinType:"Shrimp", proteinHeavy:true, carbHeavy:false, ingredients:["1 lb large shrimp, peeled & deveined","12 oz linguine","4 cloves garlic, minced","4 tbsp butter","½ cup chicken broth","1 lemon, juiced","Fresh parsley","Salt & pepper"], steps:["Cook linguine per package. Reserve ½ cup pasta water before draining.","Melt butter in a large skillet over medium heat. Add garlic, cook 1 min.","Add shrimp. Cook 2 min per side until pink.","Add chicken broth and lemon juice. Simmer 2 min.","Toss with pasta, add pasta water to loosen. Top with fresh parsley."], pickyVersion:"Plain buttered pasta with shrimp on the side.", portionNotes:"Toddlers: shrimp cut small + pasta. Kids: small portion. Teens & adults: full bowl.", veggieAlt:{ meal:"Garlic Butter Mushroom Pasta", prepTime:"5 min", cookTime:"15 min", cost:"+$3", calories:440, protein:"14g", carbs:"58g", fat:"16g", fiber:"4g", ingredients:["12 oz linguine","2 cups sliced cremini mushrooms","4 cloves garlic, minced","4 tbsp butter","½ cup vegetable broth","1 lemon","½ cup parmesan"], steps:["Cook linguine per package.","Sauté mushrooms in butter until golden, 5 min.","Add garlic 1 min, then broth + lemon juice. Simmer 2 min.","Toss with pasta and parmesan.","Add pasta water to loosen. Serve immediately."], vegNote:"Same skillet, same butter — mushrooms instead of shrimp!" } }, { id:9, meal:"Turkey & Veggie Stir Fry", description:"Lean, fast, and packed with colorful vegetables your family will actually eat.", prepTime:"10 min", cookTime:"15 min", cost:"$10–12", calories:410, protein:"34g", carbs:"32g", fat:"12g", fiber:"5g", proteinType:"Turkey", proteinHeavy:true, carbHeavy:false, ingredients:["1 lb ground turkey","2 cups broccoli florets","1 red bell pepper, sliced","1 cup snap peas","3 tbsp soy sauce","1 tbsp sesame oil","2 cloves garlic","1 tsp fresh ginger","Cooked rice to serve"], steps:["Cook turkey in sesame oil over high heat until done. Set aside.","Add garlic and ginger, cook 30 sec.","Add broccoli, pepper and snap peas. Stir fry 4 min.","Return turkey, add soy sauce. Toss everything 2 min.","Serve over rice."], pickyVersion:"Plain turkey and plain rice with soy sauce served separately.", portionNotes:"Toddlers: turkey + soft veggies over rice. Kids: 1 cup. Teens & adults: 1.5 cups.", veggieAlt:{ meal:"Tofu & Veggie Stir Fry", prepTime:"10 min", cookTime:"15 min", cost:"+$2", calories:380, protein:"20g", carbs:"32g", fat:"14g", fiber:"6g", ingredients:["½ block firm tofu, cubed and pressed dry","Same vegetables as family batch","3 tbsp soy sauce","1 tbsp sesame oil","2 cloves garlic","1 tsp fresh ginger"], steps:["Fry tofu in sesame oil until golden on all sides, 5 min.","Add garlic and ginger 30 sec.","Add all vegetables from family batch. Stir fry 4 min.","Add soy sauce. Toss 2 min.","Serve over rice."], vegNote:"Same wok, same sauce — just tofu swapped in for turkey!" } }, { id:10, meal:"Egg & Potato Shakshuka", description:"Eggs poached in spiced tomato sauce — sounds fancy, couldn't be easier.", prepTime:"5 min", cookTime:"25 min", cost:"$7–9", calories:360, protein:"22g", carbs:"28g", fat:"18g", fiber:"6g", proteinType:"Eggs", proteinHeavy:false, carbHeavy:false, ingredients:["6 large eggs","2 cans diced tomatoes","1 onion, diced","3 cloves garlic","1 bell pepper","1 tsp cumin","1 tsp paprika","½ tsp cayenne (optional)","Crusty bread to serve"], steps:["Sauté onion and pepper in olive oil 5 min.","Add garlic, cumin, paprika and cayenne. Cook 1 min.","Add both cans of tomatoes. Simmer 10 min until thickened.","Make 6 wells in the sauce, crack an egg into each.","Cover and cook 8–10 min until whites are set. Serve with bread."], pickyVersion:"Set aside plain scrambled eggs and plain tomato sauce separately.", portionNotes:"Toddlers: scrambled egg + mild sauce. Kids: 1 egg. Teens & adults: 2 eggs.", veggieAlt:null }, { id:11, meal:"One-Pot Chicken & Rice", description:"Tender chicken and fluffy rice cooked together — pure comfort.", prepTime:"10 min", cookTime:"30 min", cost:"$9–11", calories:480, protein:"36g", carbs:"46g", fat:"12g", fiber:"2g", proteinType:"Chicken", proteinHeavy:true, carbHeavy:false, ingredients:["6 bone-in chicken thighs","1½ cups long grain rice","2½ cups chicken broth","1 onion, diced","3 cloves garlic","1 tsp paprika","1 tsp cumin","Salt & pepper"], steps:["Season chicken with paprika, cumin, salt and pepper.","Brown chicken in a large pot 4 min per side. Set aside.","Cook onion and garlic in same pot 2 min.","Add rice and broth. Nestle chicken on top.","Cover and simmer 25 min until rice is fully cooked."], pickyVersion:"Plain chicken with plain rice from the bottom of the pot.", portionNotes:"Toddlers: shredded chicken + ½ cup rice. Kids: 1 thigh + rice. Teens & adults: 1–2 thighs.", veggieAlt:{ meal:"Veggie & Bean Rice Pot", prepTime:"5 min", cookTime:"25 min", cost:"+$2", calories:420, protein:"16g", carbs:"62g", fat:"8g", fiber:"12g", ingredients:["1 can chickpeas, drained","1 cup long grain rice","2 cups vegetable broth","1 cup diced tomatoes","1 zucchini, diced","1 tsp paprika","1 tsp cumin"], steps:["Sauté zucchini in olive oil 3 min.","Add paprika and cumin, cook 1 min.","Add rice, broth, tomatoes and chickpeas.","Bring to boil, cover and simmer 20 min.","Fluff with a fork and serve."], vegNote:"Same pot style — just beans and veggies instead of chicken!" } }, { id:12, meal:"Creamy Tuscan Pasta", description:"A rich, restaurant-worthy pasta that comes together in under 30 minutes.", prepTime:"8 min", cookTime:"20 min", cost:"$9–11", calories:560, protein:"24g", carbs:"58g", fat:"22g", fiber:"3g", proteinType:"Chicken", proteinHeavy:false, carbHeavy:true, ingredients:["12 oz penne pasta","1 lb chicken breast, sliced","2 cups baby spinach","1 can diced tomatoes, drained","1 cup heavy cream","3 cloves garlic, minced","½ cup parmesan","2 tbsp butter","1 tsp Italian seasoning"], steps:["Cook pasta per package. Reserve ½ cup pasta water before draining.","Cook sliced chicken in butter 4 min per side. Set aside.","In same pan cook garlic 1 min, add tomatoes + Italian seasoning 3 min.","Add cream, simmer. Stir in spinach until wilted.","Add pasta, chicken and parmesan. Toss, use pasta water to loosen."], pickyVersion:"Plain buttered pasta with chicken on the side before adding cream sauce.", portionNotes:"Toddlers: ½ cup pasta, sauce on side. Kids: 1 cup. Teens & adults: 1.5–2 cups.", veggieAlt:{ meal:"Cheesy White Bean Spinach Pasta", prepTime:"5 min", cookTime:"20 min", cost:"+$2", calories:510, protein:"24g", carbs:"62g", fat:"16g", fiber:"9g", ingredients:["12 oz penne","1 can white beans, drained","3 cups baby spinach","4 cloves garlic, minced","1 cup parmesan","½ cup pasta water","2 tbsp olive oil"], steps:["Cook pasta, reserve 1 cup pasta water.","Heat olive oil, cook garlic 1 min.","Add white beans + Italian seasoning. Mash half lightly.","Add spinach until wilted. Add pasta + pasta water.","Stir in parmesan until creamy."], vegNote:"Same pasta — white beans take the place of chicken beautifully!" } }, { id:13, meal:"Slow Cooker Pot Roast", description:"Set it in the morning — fall-apart tender roast by dinner. The house will smell incredible.", prepTime:"15 min", cookTime:"8 hrs", cost:"$14–16", calories:540, protein:"48g", carbs:"24g", fat:"24g", fiber:"4g", proteinType:"Beef", proteinHeavy:true, carbHeavy:false, ingredients:["3 lb chuck roast","4 medium potatoes, quartered","4 carrots, chopped","1 onion, quartered","2 cups beef broth","2 tbsp Worcestershire sauce","1 tsp garlic powder","Salt & pepper"], steps:["Season roast generously with salt, pepper and garlic powder.","Sear roast in a hot skillet 3 min per side.","Place vegetables in slow cooker. Set roast on top.","Pour broth and Worcestershire over everything.","Cook on LOW 8 hours. Shred and serve with vegetables."], pickyVersion:"Plain shredded beef with plain potatoes on the side.", portionNotes:"Toddlers: shredded beef + soft potato pieces. Kids: 4 oz + veggies. Teens & adults: 6–8 oz.", veggieAlt:{ meal:"Veggie Pot Pie in a Bowl", prepTime:"10 min", cookTime:"25 min", cost:"+$4", calories:480, protein:"14g", carbs:"58g", fat:"18g", fiber:"8g", ingredients:["1 can mixed vegetables, drained","1 can white beans, drained","1 cup vegetable broth","½ cup heavy cream","1 tbsp butter","1 tbsp flour","½ tsp garlic powder","2 refrigerator biscuits, baked"], steps:["Melt butter in small saucepan. Whisk in flour, cook 1 min.","Add broth and cream, stir until thickened.","Add vegetables, beans and garlic powder. Simmer 8 min.","Season to taste with salt and pepper.","Ladle into a bowl and top with a split baked biscuit."], vegNote:"While the pot roast slow cooks, this comes together on the stovetop in 30 min!" } }, { id:14, meal:"Turkey Meatball Soup", description:"Cozy, nourishing, and the kind of meal that wraps you in a warm hug.", prepTime:"15 min", cookTime:"20 min", cost:"$10–12", calories:390, protein:"30g", carbs:"36g", fat:"12g", fiber:"5g", proteinType:"Turkey", proteinHeavy:true, carbHeavy:false, ingredients:["1 lb ground turkey","1 egg","¼ cup breadcrumbs","4 cups chicken broth","2 cups egg noodles","1 cup frozen peas & carrots","1 tsp Italian seasoning","Salt & pepper"], steps:["Mix turkey, egg, breadcrumbs, salt and pepper. Roll into 1-inch meatballs.","Brown meatballs in a pot 5 min. Set aside.","Bring broth to a boil in the same pot.","Add noodles, cook 5 min. Add meatballs and veggies.","Simmer 5 more min. Season to taste and serve."], pickyVersion:"Plain meatballs and plain noodles in broth — no mixed vegetables.", portionNotes:"Toddlers: soft meatballs + noodles. Kids: 4–5 meatballs. Teens & adults: 6–8 meatballs.", veggieAlt:{ meal:"White Bean & Veggie Soup", prepTime:"5 min", cookTime:"20 min", cost:"+$2", calories:320, protein:"16g", carbs:"42g", fat:"8g", fiber:"12g", ingredients:["2 cans white beans","4 cups vegetable broth","2 cups baby spinach","1 can diced tomatoes","2 cloves garlic","1 tsp Italian seasoning","2 cups egg noodles"], steps:["Sauté garlic in olive oil 1 min.","Add broth, tomatoes, beans and Italian seasoning.","Bring to a boil, add noodles, cook 5 min.","Stir in spinach until wilted.","Season and serve with crusty bread."], vegNote:"Same broth style — white beans give it plenty of protein!" } }, { id:15, meal:"Shrimp Tacos with Avocado Slaw", description:"Light, fresh, and on the table in under 20 minutes.", prepTime:"10 min", cookTime:"8 min", cost:"$13–15", calories:420, protein:"28g", carbs:"38g", fat:"14g", fiber:"4g", proteinType:"Shrimp", proteinHeavy:true, carbHeavy:false, ingredients:["1.5 lbs shrimp, peeled & deveined","8 small corn tortillas","1½ cups coleslaw mix","½ avocado, mashed","1 lime","1 tsp chili powder","1 tsp garlic powder","Fresh cilantro"], steps:["Season shrimp with chili powder, garlic powder, salt.","Cook shrimp in skillet 2 min per side until pink.","Mix coleslaw with mashed avocado and lime juice.","Warm tortillas in a dry pan.","Layer slaw, shrimp and cilantro in each tortilla."], pickyVersion:"Plain shrimp in plain tortillas — no slaw or avocado.", portionNotes:"Toddlers: shrimp pieces, no shell. Kids: 2 tacos. Teens & adults: 3 tacos.", veggieAlt:{ meal:"Crispy Chickpea Tacos", prepTime:"5 min", cookTime:"15 min", cost:"+$2", calories:400, protein:"14g", carbs:"52g", fat:"14g", fiber:"10g", ingredients:["1 can chickpeas, drained & dried","8 small corn tortillas","1 tsp chili powder","½ tsp cumin","½ tsp garlic powder","Same avocado slaw as the family"], steps:["Toss chickpeas with chili powder, cumin, garlic powder and olive oil.","Roast at 425°F for 20 min until crispy.","Warm tortillas in a dry pan.","Fill with crispy chickpeas and avocado slaw.","Squeeze lime over top."], vegNote:"Same tortillas, same slaw — chickpeas bring the crunch!" } }, { id:16, meal:"Baked Chicken Parmesan", description:"A family classic — crispy chicken smothered in marinara and melted cheese.", prepTime:"15 min", cookTime:"25 min", cost:"$11–13", calories:550, protein:"44g", carbs:"36g", fat:"22g", fiber:"3g", proteinType:"Chicken", proteinHeavy:true, carbHeavy:false, ingredients:["4 chicken breasts","1 cup marinara sauce","1 cup shredded mozzarella","½ cup breadcrumbs","¼ cup parmesan","1 egg, beaten","1 tsp Italian seasoning","Spaghetti to serve"], steps:["Preheat oven to 400°F. Pound chicken to even thickness.","Dip chicken in egg, then coat in breadcrumbs mixed with parmesan.","Bake chicken on oiled pan 20 min until cooked through.","Top with marinara and mozzarella. Bake 5 more min until bubbly.","Serve over spaghetti."], pickyVersion:"Plain breaded chicken with marinara and cheese on the side.", portionNotes:"Toddlers: small cut pieces. Kids: ½ breast. Teens & adults: 1 full breast.", veggieAlt:{ meal:"Eggplant Parmesan", prepTime:"15 min", cookTime:"30 min", cost:"+$3", calories:420, protein:"18g", carbs:"42g", fat:"20g", fiber:"6g", ingredients:["1 large eggplant, sliced ½ inch","1 cup marinara sauce","1 cup shredded mozzarella","½ cup breadcrumbs","¼ cup parmesan","1 egg, beaten"], steps:["Salt eggplant slices, let sit 10 min, pat dry.","Dip in egg, coat in breadcrumbs + parmesan.","Bake at 400°F 20 min, flipping halfway.","Top with marinara and mozzarella. Bake 10 more min.","Serve over spaghetti."], vegNote:"Same breading, same oven — eggplant is a beautiful swap!" } }, { id:17, meal:"Pork & Green Bean Stir Fry", description:"Quick weeknight stir fry with tender pork and crisp green beans.", prepTime:"10 min", cookTime:"15 min", cost:"$10–12", calories:430, protein:"36g", carbs:"22g", fat:"16g", fiber:"4g", proteinType:"Pork", proteinHeavy:true, carbHeavy:false, ingredients:["1 lb pork tenderloin, thinly sliced","2 cups green beans, trimmed","1 red bell pepper, sliced","3 tbsp soy sauce","2 tbsp oyster sauce","1 tbsp sesame oil","3 cloves garlic","1 tsp ginger","Cooked rice to serve"], steps:["Cook pork in sesame oil over high heat 3–4 min. Set aside.","Add garlic and ginger 30 sec.","Add green beans and pepper. Stir fry 4 min.","Return pork, add soy sauce and oyster sauce. Toss 2 min.","Serve over rice."], pickyVersion:"Plain pork and plain rice with soy sauce on the side.", portionNotes:"Toddlers: tender pork + soft veggies over rice. Kids: 1 cup. Teens & adults: 1.5 cups.", veggieAlt:{ meal:"Tofu & Green Bean Stir Fry", prepTime:"10 min", cookTime:"15 min", cost:"+$2", calories:360, protein:"18g", carbs:"22g", fat:"14g", fiber:"5g", ingredients:["½ block firm tofu, sliced","Same vegetables as family batch","3 tbsp soy sauce","2 tbsp oyster sauce (or hoisin)","1 tbsp sesame oil","3 cloves garlic"], steps:["Press tofu dry. Cook in sesame oil until golden, 4 min.","Add garlic 30 sec.","Add vegetables from family batch. Stir fry 4 min.","Add soy sauce and hoisin. Toss 2 min.","Serve over rice."], vegNote:"Same wok, same sauce — tofu takes just as long as the pork!" } }, { id:18, meal:"Fish Tacos with Mango Salsa", description:"Fresh, bright, and summery — a new family favorite waiting to happen.", prepTime:"15 min", cookTime:"10 min", cost:"$13–14", calories:400, protein:"30g", carbs:"36g", fat:"12g", fiber:"4g", proteinType:"Fish", proteinHeavy:true, carbHeavy:false, ingredients:["1.5 lbs white fish (tilapia or cod)","8 small corn tortillas","1 mango, diced","½ red onion, diced finely","1 lime","1 tsp chili powder","1 tsp garlic powder","Fresh cilantro"], steps:["Season fish with chili powder, garlic powder, salt.","Cook fish in skillet 3–4 min per side until flaky.","Mix mango, red onion, cilantro and lime juice.","Warm tortillas in a dry pan.","Break fish into pieces, fill tacos and top with mango salsa."], pickyVersion:"Plain fish in plain tortillas — skip the mango salsa.", portionNotes:"Toddlers: fish broken into small pieces. Kids: 2 tacos. Teens & adults: 2–3 tacos.", veggieAlt:null }, { id:19, meal:"Chicken & Broccoli Casserole", description:"The cozy casserole everyone grew up on — pure comfort in a dish.", prepTime:"15 min", cookTime:"30 min", cost:"$10–12", calories:510, protein:"38g", carbs:"34g", fat:"20g", fiber:"4g", proteinType:"Chicken", proteinHeavy:true, carbHeavy:false, ingredients:["2 cups cooked chicken, shredded","3 cups broccoli florets","1 can cream of chicken soup","½ cup sour cream","1 cup shredded cheddar","1 cup egg noodles, cooked","½ tsp garlic powder","Salt & pepper"], steps:["Preheat oven to 375°F. Lightly grease a 9x13 baking dish.","Mix chicken soup, sour cream, garlic powder, salt and pepper.","Toss in chicken, broccoli, and cooked noodles. Mix well.","Pour into baking dish. Top with shredded cheddar.","Bake 25–30 min until bubbly and golden on top."], pickyVersion:"Plate plain chicken and plain noodles before mixing in the sauce.", portionNotes:"Toddlers: small spoonful, let cool. Kids: ¾ cup. Teens & adults: 1–1.5 cups.", veggieAlt:{ meal:"Broccoli & Cheese Egg Casserole", prepTime:"10 min", cookTime:"30 min", cost:"+$2", calories:380, protein:"22g", carbs:"24g", fat:"22g", fiber:"4g", ingredients:["6 large eggs","3 cups broccoli florets","1 cup shredded cheddar","½ cup sour cream","½ cup milk","1 cup cooked egg noodles","½ tsp garlic powder"], steps:["Preheat oven to 375°F. Grease a small baking dish.","Whisk eggs, sour cream, milk and garlic powder.","Fold in broccoli, noodles and half the cheese.","Pour into dish. Top with remaining cheese.","Bake 25–28 min until eggs are set and top is golden."], vegNote:"Same dish, same oven — eggs make this just as hearty!" } }, { id:20, meal:"Beef & Broccoli over Rice", description:"The classic takeout dish — made at home in 20 minutes for a fraction of the price.", prepTime:"10 min", cookTime:"15 min", cost:"$11–13", calories:470, protein:"34g", carbs:"42g", fat:"14g", fiber:"4g", proteinType:"Beef", proteinHeavy:true, carbHeavy:false, ingredients:["1 lb flank steak, thinly sliced","3 cups broccoli florets","3 tbsp soy sauce","2 tbsp oyster sauce","1 tbsp sesame oil","2 tsp cornstarch","2 cloves garlic","1 tsp ginger","Cooked rice to serve"], steps:["Mix soy sauce, oyster sauce, cornstarch and ½ cup water. Set aside.","Cook beef in sesame oil over high heat 3 min. Set aside.","Stir fry garlic and ginger 30 sec. Add broccoli 4 min.","Return beef, pour in sauce. Toss and cook 2 min until thickened.","Serve over rice."], pickyVersion:"Plain beef and plain broccoli over rice — sauce on the side.", portionNotes:"Toddlers: soft broccoli + beef over rice. Kids: 1 cup. Teens & adults: 1.5 cups.", veggieAlt:{ meal:"Crispy Tofu & Broccoli over Rice", prepTime:"10 min", cookTime:"15 min", cost:"+$3", calories:400, protein:"22g", carbs:"42g", fat:"14g", fiber:"5g", ingredients:["½ block firm tofu, cubed","3 cups broccoli (from family batch)","Same sauce as the family","1 tbsp sesame oil","2 cloves garlic"], steps:["Press tofu dry. Cook in sesame oil until golden, 5 min.","Stir fry garlic 30 sec. Add broccoli from family batch 4 min.","Pour sauce over everything. Toss 2 min until coated.","Taste and adjust seasoning.","Serve over rice."], vegNote:"Same sauce, same broccoli — crispy tofu is the star!" } }, { id:21, meal:"Lemon Chicken Piccata", description:"Bright, buttery, restaurant-worthy — and ready in 25 minutes.", prepTime:"10 min", cookTime:"15 min", cost:"$11–13", calories:460, protein:"40g", carbs:"18g", fat:"22g", fiber:"1g", proteinType:"Chicken", proteinHeavy:true, carbHeavy:false, ingredients:["4 chicken breasts, pounded thin","½ cup flour","4 tbsp butter","¼ cup capers","½ cup chicken broth","1 lemon, juiced","2 cloves garlic","Salt & pepper","Pasta or rice to serve"], steps:["Season chicken with salt and pepper, dredge in flour.","Cook chicken in butter 3–4 min per side until golden. Set aside.","Add garlic to pan 1 min. Add broth, lemon juice and capers.","Simmer 3 min until slightly reduced.","Return chicken to pan, coat in sauce. Serve over pasta or rice."], pickyVersion:"Plain pan-cooked chicken with butter and plain pasta or rice.", portionNotes:"Toddlers: cut small, sauce on the side. Kids: ½ breast. Teens & adults: 1 breast.", veggieAlt:null }, { id:22, meal:"Beef Stuffed Bell Peppers", description:"A fun, colorful dinner the whole family gets their own pepper.", prepTime:"15 min", cookTime:"35 min", cost:"$11–13", calories:490, protein:"34g", carbs:"38g", fat:"18g", fiber:"5g", proteinType:"Beef", proteinHeavy:true, carbHeavy:false, ingredients:["4 large bell peppers, tops removed","1 lb ground beef","1 cup cooked rice","1 can diced tomatoes, drained","1 cup shredded cheddar","1 tsp garlic powder","1 tsp Italian seasoning","Salt & pepper"], steps:["Preheat oven to 375°F. Hollow out peppers, place in baking dish.","Brown beef, drain fat. Mix in rice, tomatoes, garlic powder, Italian seasoning.","Stuff each pepper generously with beef mixture.","Top each with shredded cheddar.","Cover with foil, bake 25 min. Remove foil, bake 10 more min."], pickyVersion:"Serve filling alongside the pepper rather than stuffed — kids can pick what they like.", portionNotes:"Toddlers: filling only, no pepper. Kids: half a pepper. Teens & adults: 1 full pepper.", veggieAlt:{ meal:"Veggie & Bean Stuffed Peppers", prepTime:"10 min", cookTime:"35 min", cost:"+$2", calories:420, protein:"16g", carbs:"52g", fat:"14g", fiber:"10g", ingredients:["2 bell peppers, tops removed","1 can black beans, drained","1 cup cooked rice","½ cup corn","½ cup diced tomatoes","½ cup shredded cheddar","1 tsp cumin"], steps:["Preheat oven to 375°F. Place peppers in small baking dish.","Mix beans, rice, corn, tomatoes and cumin.","Stuff peppers, top with cheddar.","Cover with foil, bake 25 min. Uncover 10 more min.","Let cool slightly before serving."], vegNote:"Same oven, same time — they bake right alongside the beef peppers!" } }, { id:23, meal:"Chicken Enchiladas", description:"Cheesy, saucy, crowd-pleasing — a dish nobody can say no to.", prepTime:"20 min", cookTime:"25 min", cost:"$12–14", calories:530, protein:"34g", carbs:"48g", fat:"20g", fiber:"6g", proteinType:"Chicken", proteinHeavy:true, carbHeavy:false, ingredients:["2 lbs chicken breast, cooked & shredded","8 flour tortillas","2 cans red enchilada sauce","2 cups shredded Mexican cheese","1 can black beans, drained","1 tsp cumin","1 tsp garlic powder","Sour cream to serve"], steps:["Preheat oven to 375°F. Mix chicken with cumin, garlic powder and ½ cup enchilada sauce.","Fill each tortilla with chicken, black beans and cheese. Roll tight.","Place seam-down in a greased baking dish.","Pour remaining enchilada sauce over top. Cover with remaining cheese.","Bake 25 min until bubbly. Serve with sour cream."], pickyVersion:"Set aside plain chicken and cheese in a plain tortilla before adding enchilada sauce.", portionNotes:"Toddlers: deconstructed filling. Kids: 1 enchilada. Teens & adults: 2 enchiladas.", veggieAlt:{ meal:"Cheese & Bean Enchiladas", prepTime:"10 min", cookTime:"25 min", cost:"+$2", calories:470, protein:"18g", carbs:"58g", fat:"18g", fiber:"10g", ingredients:["2 flour tortillas","½ can black beans","½ cup corn","½ cup enchilada sauce","½ cup shredded Mexican cheese","Sour cream to serve"], steps:["Mix beans and corn together.","Fill tortillas with bean mixture and cheese. Roll tight.","Place seam-down in small greased dish.","Pour enchilada sauce over top. Add remaining cheese.","Bake at 375°F for 25 min until bubbly."], vegNote:"Same dish, same oven — uses the same tortillas and cheese!" } }, { id:24, meal:"Pork Carnitas Rice Bowls", description:"Slow-cooked, crispy-edged carnitas served as a build-your-own bowl night.", prepTime:"15 min", cookTime:"4 hrs", cost:"$12–14", calories:520, protein:"38g", carbs:"42g", fat:"18g", fiber:"5g", proteinType:"Pork", proteinHeavy:true, carbHeavy:false, ingredients:["2 lbs pork shoulder","1 orange, juiced","1 lime, juiced","1 tsp cumin","1 tsp garlic powder","1 tsp oregano","Cooked rice, black beans, shredded cheese, sour cream to serve"], steps:["Season pork with cumin, garlic powder, oregano, salt, pepper.","Place in slow cooker with orange and lime juice.","Cook on HIGH 4 hours or LOW 7 hours.","Shred pork and crisp under broiler 5 min.","Serve over rice with beans, cheese and sour cream."], pickyVersion:"Plain shredded pork over plain rice — toppings on the side.", portionNotes:"Toddlers: shredded pork + rice. Kids: small bowl. Teens & adults: full bowl.", veggieAlt:{ meal:"Cilantro Lime Black Bean Bowls", prepTime:"5 min", cookTime:"10 min", cost:"+$2", calories:440, protein:"16g", carbs:"62g", fat:"10g", fiber:"14g", ingredients:["1 can black beans, drained","Cooked rice","1 lime, juiced","½ tsp cumin","Fresh cilantro","Shredded cheese, sour cream (from family spread)"], steps:["Heat beans with cumin and lime juice 5 min.","Cook rice if not already done.","Build bowls: rice, beans, cheese, sour cream.","Top with fresh cilantro and extra lime.","Set out same toppings as the family carnitas bar!"], vegNote:"Same toppings bar as the carnitas — just swap beans for pork!" } }, { id:25, meal:"Baked Salmon with Dill Sauce", description:"Elegant enough for guests, easy enough for any Tuesday.", prepTime:"5 min", cookTime:"18 min", cost:"$14–16", calories:430, protein:"44g", carbs:"6g", fat:"24g", fiber:"1g", proteinType:"Fish", proteinHeavy:true, carbHeavy:false, ingredients:["4 salmon fillets","2 tbsp olive oil","Salt & pepper","For sauce: ½ cup Greek yogurt","1 tbsp fresh dill","1 lemon, juiced","1 clove garlic, minced"], steps:["Preheat oven to 400°F. Season salmon with olive oil, salt, pepper.","Place in foil-lined baking dish. Bake 15–18 min until flaky.","While salmon bakes, mix yogurt, dill, lemon juice and garlic.","Plate salmon and spoon dill sauce generously over top.","Serve with roasted asparagus or steamed vegetables."], pickyVersion:"Plain baked salmon with no sauce — just a little butter.", portionNotes:"Toddlers: flaked, small pieces. Kids: 3 oz. Teens & adults: 5–6 oz.", veggieAlt:null }, { id:26, meal:"Ground Turkey Lettuce Wraps", description:"Fresh, fun and interactive — kids love building their own wraps.", prepTime:"10 min", cookTime:"12 min", cost:"$10–11", calories:380, protein:"32g", carbs:"20g", fat:"14g", fiber:"3g", proteinType:"Turkey", proteinHeavy:true, carbHeavy:false, ingredients:["1 lb ground turkey","1 head butter lettuce, leaves separated","1 cup water chestnuts, diced","3 green onions, sliced","3 tbsp soy sauce","1 tbsp hoisin sauce","1 tbsp sesame oil","2 cloves garlic","1 tsp ginger"], steps:["Cook turkey in sesame oil over medium-high heat until done.","Add garlic and ginger, cook 1 min.","Add water chestnuts and green onions, stir 2 min.","Add soy sauce and hoisin, toss everything together.","Serve in lettuce cups — everyone builds their own!"], pickyVersion:"Plain turkey served in a tortilla with hoisin on the side.", portionNotes:"Toddlers: filling on a plate, no wrap. Kids: 2–3 wraps. Teens & adults: 3–4 wraps.", veggieAlt:{ meal:"Mushroom & Lentil Lettuce Wraps", prepTime:"5 min", cookTime:"15 min", cost:"+$2", calories:320, protein:"16g", carbs:"32g", fat:"10g", fiber:"8g", ingredients:["1 cup cooked lentils","1 cup mushrooms, finely diced","Same sauce as family batch","Butter lettuce leaves"], steps:["Cook mushrooms in sesame oil until browned, 5 min.","Add cooked lentils, garlic and ginger. Cook 2 min.","Add soy sauce and hoisin. Toss together.","Spoon into lettuce cups.","Serve with any remaining toppings from the family spread."], vegNote:"Same lettuce cups, same sauce — lentils + mushrooms are deeply satisfying!" } }, { id:27, meal:"Spaghetti & Meat Sauce", description:"The dinner that never fails — a classic every family comes back to.", prepTime:"5 min", cookTime:"25 min", cost:"$9–11", calories:510, protein:"30g", carbs:"58g", fat:"14g", fiber:"5g", proteinType:"Beef", proteinHeavy:false, carbHeavy:true, ingredients:["1 lb ground beef","1 lb spaghetti","1 jar (24 oz) marinara sauce","1 onion, diced","3 cloves garlic","1 tsp Italian seasoning","½ tsp sugar","Parmesan to serve"], steps:["Cook spaghetti per package. Drain and set aside.","Brown beef with onion, drain fat.","Add garlic and Italian seasoning, cook 1 min.","Add marinara and sugar. Simmer 15 min.","Serve over spaghetti with parmesan."], pickyVersion:"Plain buttered spaghetti with meat sauce served on the side.", portionNotes:"Toddlers: pasta cut small, mild sauce. Kids: 1 cup. Teens & adults: 1.5–2 cups.", veggieAlt:{ meal:"Spaghetti with Veggie Marinara", prepTime:"5 min", cookTime:"20 min", cost:"+$1", calories:440, protein:"14g", carbs:"68g", fat:"10g", fiber:"6g", ingredients:["Spaghetti (from family batch)","1 cup marinara (from family jar)","½ zucchini, diced","½ cup mushrooms, diced","2 cloves garlic","Parmesan to finish"], steps:["Sauté zucchini and mushrooms in olive oil 5 min.","Add garlic 1 min, then add marinara.","Simmer 10 min.","Serve over spaghetti with parmesan.","Add extra veggies if desired."], vegNote:"Same pasta, same marinara jar — just loaded with veggies!" } }, { id:28, meal:"Teriyaki Chicken Bowls", description:"Sweet, sticky teriyaki over fluffy rice — a weeknight superstar.", prepTime:"10 min", cookTime:"20 min", cost:"$10–12", calories:480, protein:"36g", carbs:"50g", fat:"10g", fiber:"2g", proteinType:"Chicken", proteinHeavy:true, carbHeavy:false, ingredients:["1.5 lbs chicken thighs, boneless","¼ cup soy sauce","2 tbsp honey","1 tbsp mirin or rice vinegar","1 tsp garlic powder","1 tsp cornstarch","Cooked rice & steamed broccoli to serve"], steps:["Mix soy sauce, honey, mirin, garlic powder and cornstarch.","Cook chicken in a lightly oiled pan 5 min per side.","Pour sauce over chicken, cook 3–4 more min until glazed.","Let rest 3 min before slicing.","Serve over rice with steamed broccoli."], pickyVersion:"Plain pan-cooked chicken over plain rice — teriyaki sauce on the side.", portionNotes:"Toddlers: sliced thin over rice. Kids: 1 thigh + rice. Teens & adults: 1–2 thighs.", veggieAlt:{ meal:"Teriyaki Tofu Bowls", prepTime:"10 min", cookTime:"15 min", cost:"+$2", calories:400, protein:"20g", carbs:"50g", fat:"12g", fiber:"3g", ingredients:["½ block firm tofu, sliced","Same teriyaki sauce as family","Cooked rice + steamed broccoli (from family batch)"], steps:["Press tofu dry. Pan fry in oil 3–4 min per side until golden.","Pour teriyaki sauce over tofu, cook 3 min until glazed.","Slice into strips.","Serve over rice with steamed broccoli.","Sesame seeds on top for a nice finish."], vegNote:"Same sauce, same bowl — tofu soaks up teriyaki beautifully!" } }, { id:29, meal:"Pork Fried Noodles", description:"Savory, satisfying noodles — better than your favorite noodle house.", prepTime:"10 min", cookTime:"15 min", cost:"$10–12", calories:500, protein:"32g", carbs:"54g", fat:"16g", fiber:"3g", proteinType:"Pork", proteinHeavy:false, carbHeavy:true, ingredients:["1 lb ground pork","8 oz lo mein noodles","2 cups shredded cabbage","1 cup shredded carrots","3 tbsp soy sauce","2 tbsp oyster sauce","1 tbsp sesame oil","3 cloves garlic","2 eggs, beaten"], steps:["Cook noodles per package. Drain and toss with a little sesame oil.","Cook pork in sesame oil over high heat. Set aside.","Cook garlic 30 sec. Add cabbage and carrots, stir fry 3 min.","Push veggies aside, scramble eggs in center.","Add noodles, pork, soy sauce and oyster sauce. Toss over high heat 2 min."], pickyVersion:"Plain noodles with butter and a little soy sauce for dipping.", portionNotes:"Toddlers: soft noodles + pork, cut small. Kids: 1 cup. Teens & adults: 1.5 cups.", veggieAlt:{ meal:"Veggie Lo Mein", prepTime:"10 min", cookTime:"12 min", cost:"+$2", calories:420, protein:"14g", carbs:"60g", fat:"12g", fiber:"5g", ingredients:["Lo mein noodles (from family batch)","Cabbage & carrots (from family batch)","2 eggs, beaten","3 tbsp soy sauce","2 tbsp oyster sauce or hoisin","1 tbsp sesame oil"], steps:["Cook noodles and toss with sesame oil.","Stir fry cabbage and carrots in sesame oil 3 min.","Push aside and scramble eggs.","Add noodles, soy sauce and oyster sauce. Toss 2 min.","Serve hot."], vegNote:"Same wok, same noodles — just skip the pork!" } }, { id:30, meal:"Honey Mustard Baked Chicken", description:"Simple, family-friendly chicken with a sweet tang everyone loves.", prepTime:"5 min", cookTime:"30 min", cost:"$10–12", calories:460, protein:"40g", carbs:"16g", fat:"20g", fiber:"0g", proteinType:"Chicken", proteinHeavy:true, carbHeavy:false, ingredients:["4 chicken breasts","3 tbsp honey","2 tbsp Dijon mustard","1 tbsp olive oil","1 tsp garlic powder","Salt & pepper","Roasted potatoes to serve"], steps:["Preheat oven to 400°F.","Mix honey, Dijon mustard, olive oil and garlic powder.","Season chicken with salt and pepper, place in baking dish.","Spoon honey mustard mixture generously over chicken.","Bake 28–30 min until cooked through and golden on top."], pickyVersion:"Plain baked chicken with honey mustard on the side for dipping.", portionNotes:"Toddlers: cut small. Kids: ½ breast. Teens & adults: 1 breast.", veggieAlt:null }, { id:31, meal:"Beef Bulgogi Bowls", description:"Korean-inspired sweet-savory beef over rice — a serious crowd-pleaser.", prepTime:"15 min", cookTime:"10 min", cost:"$12–14", calories:490, protein:"34g", carbs:"48g", fat:"14g", fiber:"3g", proteinType:"Beef", proteinHeavy:true, carbHeavy:false, ingredients:["1 lb ribeye or sirloin, thinly sliced","¼ cup soy sauce","2 tbsp brown sugar","1 tbsp sesame oil","4 cloves garlic, minced","1 tsp ginger","2 green onions","Cooked rice & sesame seeds to serve"], steps:["Mix soy sauce, brown sugar, sesame oil, garlic and ginger.","Marinate beef in sauce 10 min (or longer if you have time).","Cook beef in a hot pan 2–3 min per side — cook in batches.","Top with sliced green onions and sesame seeds.","Serve over rice."], pickyVersion:"Plain beef over plain rice — bulgogi sauce on the side.", portionNotes:"Toddlers: small pieces over rice. Kids: small bowl. Teens & adults: full bowl.", veggieAlt:{ meal:"Mushroom Bulgogi Bowls", prepTime:"10 min", cookTime:"10 min", cost:"+$3", calories:380, protein:"10g", carbs:"52g", fat:"12g", fiber:"4g", ingredients:["2 cups portobello mushrooms, sliced","Same bulgogi sauce as family","Cooked rice (from family batch)","Green onions + sesame seeds"], steps:["Marinate mushrooms in bulgogi sauce 10 min.","Cook in hot pan 3–4 min per side.","Plate over rice.","Top with green onions and sesame seeds.","Serve immediately."], vegNote:"Same marinade, same bowl — mushrooms soak up the bulgogi sauce like magic!" } }, { id:32, meal:"Baked Cod with Lemon & Capers", description:"Flaky, flavorful cod that's ready in 20 minutes — so much easier than it looks.", prepTime:"5 min", cookTime:"15 min", cost:"$12–14", calories:380, protein:"40g", carbs:"8g", fat:"16g", fiber:"1g", proteinType:"Fish", proteinHeavy:true, carbHeavy:false, ingredients:["4 cod fillets","3 tbsp butter, melted","2 tbsp capers","1 lemon, zested & juiced","2 cloves garlic, minced","1 tsp dried parsley","Salt & pepper"], steps:["Preheat oven to 400°F. Line baking dish with foil.","Place cod in dish. Mix butter, capers, lemon zest, lemon juice, garlic and parsley.","Spoon mixture over cod fillets.","Bake 12–15 min until fish flakes easily.","Serve with rice or roasted potatoes."], pickyVersion:"Plain baked cod with just butter and no capers or lemon.", portionNotes:"Toddlers: flaked, no capers. Kids: 3 oz. Teens & adults: 5 oz.", veggieAlt:null }, { id:33, meal:"Chicken Tikka Masala", description:"Rich, aromatic, restaurant-quality curry — made right in your kitchen.", prepTime:"15 min", cookTime:"30 min", cost:"$12–14", calories:510, protein:"38g", carbs:"28g", fat:"22g", fiber:"4g", proteinType:"Chicken", proteinHeavy:true, carbHeavy:false, ingredients:["1.5 lbs chicken breast, cubed","1 can (14 oz) crushed tomatoes","1 cup heavy cream","1 onion, diced","3 cloves garlic","1 tbsp garam masala","1 tsp cumin","1 tsp paprika","1 tsp turmeric","Cooked rice & naan to serve"], steps:["Cook chicken in oil until browned. Set aside.","Sauté onion 5 min. Add garlic and all spices. Cook 2 min.","Add crushed tomatoes. Simmer 10 min.","Add cream, stir well. Simmer 5 more min.","Return chicken to pan. Simmer 5 min. Serve over rice."], pickyVersion:"Plain chicken over plain rice with a tiny bit of mild sauce on the side.", portionNotes:"Toddlers: very mild, small portion over rice. Kids: small bowl. Teens & adults: full bowl.", veggieAlt:{ meal:"Chickpea Tikka Masala", prepTime:"5 min", cookTime:"25 min", cost:"+$2", calories:450, protein:"16g", carbs:"50g", fat:"20g", fiber:"10g", ingredients:["2 cans chickpeas, drained","Same tikka masala sauce as family batch","Cooked rice & naan (from family)"], steps:["Make tikka masala sauce following family recipe steps 2–4.","Add chickpeas to sauce. Simmer 10 min.","Taste and adjust seasoning.","Serve over rice.","Great with naan for scooping!"], vegNote:"Same aromatic sauce — chickpeas make this incredibly satisfying!" } }, { id:34, meal:"Shrimp & Grits", description:"Southern comfort at its best — creamy grits topped with buttery shrimp.", prepTime:"10 min", cookTime:"20 min", cost:"$13–15", calories:500, protein:"34g", carbs:"44g", fat:"20g", fiber:"2g", proteinType:"Shrimp", proteinHeavy:true, carbHeavy:false, ingredients:["1 lb large shrimp, peeled","1 cup quick-cooking grits","2 cups chicken broth","1 cup shredded cheddar","4 tbsp butter","3 cloves garlic","1 tsp Cajun seasoning","2 green onions"], steps:["Cook grits in chicken broth per package. Stir in butter and cheddar.","Cook shrimp in butter with garlic and Cajun seasoning, 2 min per side.","Add a splash of broth to the pan for a light sauce.","Spoon grits into bowls. Top generously with shrimp and sauce.","Garnish with green onions."], pickyVersion:"Plain shrimp over plain grits — no Cajun seasoning.", portionNotes:"Toddlers: shrimp halved + mild grits. Kids: small bowl. Teens & adults: full bowl.", veggieAlt:null }, { id:35, meal:"Lemon Chicken Orzo Soup", description:"Light, bright, healing — the soup you didn't know you needed tonight.", prepTime:"10 min", cookTime:"25 min", cost:"$10–12", calories:420, protein:"32g", carbs:"38g", fat:"10g", fiber:"3g", proteinType:"Chicken", proteinHeavy:true, carbHeavy:false, ingredients:["1.5 lbs chicken breast","6 cups chicken broth","1 cup orzo pasta","2 lemons, juiced","2 cloves garlic","1 cup baby spinach","1 tsp dried thyme","Salt & pepper"], steps:["Poach chicken breasts in broth 15 min. Remove and shred.","Bring broth back to a boil. Add orzo, cook 8 min.","Return shredded chicken to pot.","Add lemon juice, garlic, spinach and thyme.","Season to taste and serve hot."], pickyVersion:"Plain chicken and plain orzo in broth — skip the spinach and lemon.", portionNotes:"Toddlers: small bowl with soft pasta. Kids: 1 cup. Teens & adults: 1.5–2 cups.", veggieAlt:{ meal:"Lemon White Bean & Spinach Soup", prepTime:"5 min", cookTime:"15 min", cost:"+$1", calories:340, protein:"16g", carbs:"42g", fat:"8g", fiber:"10g", ingredients:["2 cans white beans","6 cups vegetable broth","1 cup orzo","2 lemons, juiced","3 cups baby spinach","2 cloves garlic","1 tsp dried thyme"], steps:["Bring broth to a boil. Add orzo, cook 8 min.","Add white beans, garlic and thyme.","Stir in lemon juice and spinach until wilted.","Season to taste.","Serve with crusty bread."], vegNote:"Same bright lemon flavor — white beans make it just as hearty!" } }, { id:36, meal:"Homemade Margherita Pizza Night", description:"Make-your-own pizza night — the whole family gets involved and everyone wins.", prepTime:"15 min", cookTime:"15 min", cost:"$9–11", calories:480, protein:"20g", carbs:"56g", fat:"18g", fiber:"3g", proteinType:"Eggs", proteinHeavy:false, carbHeavy:true, ingredients:["1 lb store-bought pizza dough","1 cup pizza sauce","2 cups shredded mozzarella","2 roma tomatoes, sliced","Fresh basil leaves","2 tbsp olive oil","1 tsp garlic powder","Parmesan to finish"], steps:["Preheat oven to 450°F. Stretch dough onto an oiled baking sheet.","Brush with olive oil, sprinkle with garlic powder.","Spread pizza sauce leaving a border. Top with mozzarella and tomato slices.","Bake 12–15 min until crust is golden and cheese is bubbly.","Top with fresh basil and parmesan. Let cool slightly before slicing."], pickyVersion:"Plain cheese pizza with no tomato slices or basil.", portionNotes:"Toddlers: cut into small squares, cooled. Kids: 1–2 slices. Teens & adults: 2–3 slices.", veggieAlt:null }, ];

